{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"mount_file_id":"1-20daR3m88EM8dTS2YdhtipLagOYCJz9","authorship_tag":"ABX9TyOOrVB/2pFrFjNqY1lIyz3S"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"markdown","source":["Initialization"],"metadata":{"id":"Qbl4wSUZoOAB"}},{"cell_type":"code","source":["import pandas as pd\n","import numpy as np\n","import matplotlib.pyplot as plt\n","from collections import defaultdict"],"metadata":{"id":"etzqst3co2LZ","executionInfo":{"status":"ok","timestamp":1768654291506,"user_tz":-330,"elapsed":1834,"user":{"displayName":"Aayush","userId":"13805432364675088607"}}},"execution_count":1,"outputs":[]},{"cell_type":"code","source":["station_set = set()\n","station_outage_count = defaultdict(lambda: defaultdict(int))\n","station_max_outage_time = {}\n","station_total_count = {}\n","station_outage_blocks = defaultdict(lambda: defaultdict(list))\n","last_status = {}\n","last_run_length = {}\n","last_season = {}\n","master = defaultdict(lambda: defaultdict(lambda: defaultdict(lambda: {\"actual\":0,\"total\":0, \"invalid\":0})))\n","\n","upper_bounds = {\n","  \"PM2.5\": 1000,\n","  \"PM10\": 2000,\n","  \"NO\": 1500,\n","  \"NO2\": 1500,\n","  \"NOx\": 2000,\n","  \"CO\": 100,\n","  \"SO2\": 3200,\n","  \"O3\": 1500,\n","  \"NH3\": 3000,\n","  \"Benzene\": 400,\n","  \"Toluene\": 400,\n","  \"Xylene\": 400,\n","  \"AQI\": 500}\n","\n","breakpoints = {\n","'PM2.5':[(0,30,0,50),\n","  (31,60,51,100),\n","  (61,90,101,200),\n","  (91,120,201,300),\n","  (121,250,301,400),\n","  (251,1000,401,500)],\n","\n","'PM10':[(0,50,0,50),\n","  (51,100,51,100),\n","  (101,250,101,200),\n","  (251,350,201,300),\n","  (351,430,301,400),\n","  (431,2000,401,500)],\n","\n","'NO2':[(0,40,0,50),\n","  (41,80,51,100),\n","  (81,180,101,200),\n","  (181,280,201,300),\n","  (281,400,301,400),\n","  (401,1500,401,500)],\n","\n","'SO2':[(0,40,0,50),\n","  (41,80,51,100),\n","  (81,380,101,200),\n","  (381,800,201,300),\n","  (801,1600,301,400),\n","  (1601,3200,401,500)],\n","\n","\"O3\":[(0,50,0,50),\n","  (51,100,51,100),\n","  (101,168,101,200),\n","  (169,208,201,300),\n","  (209,748,301,400),\n","  (749,1500,401,500)],\n","\n","\"NH3\":[(0,200,0,50),\n","  (201,400,51,100),\n","  (401,800,101,200),\n","  (801,1200,201,300),\n","  (1201,1800,301,400),\n","  (1801,3000,401,500)],\n","\n","\"CO\":[(0,1,0,50),\n","  (1.1,2,51,100),\n","  (2.1,10,101,200),\n","  (10.1,17,201,300),\n","  (17.1,34,301,400),\n","  (34.1,100,401,500)]}\n","\n","\n","\n","def season(month):\n","  if month in [12, 1, 2]:\n","    return \"Winter\"\n","  elif month in [3, 4, 5, 6]:\n","    return \"Summer\"\n","  elif month in [7, 8, 9]:\n","    return \"Monsoon\"\n","  else:\n","    return \"Autumn\"\n","\n","def subindex(pollutant,value):\n","  if np.isnan(value):\n","    return 0\n","  for (BP_lo, BP_hi, SI_lo, SI_hi) in breakpoints[pollutant]:\n","    if BP_lo <= value <= BP_hi:\n","      SI = ((SI_hi-SI_lo)/(BP_hi-BP_lo))*(value-BP_lo) + SI_lo\n","      return SI\n","  return 500 #max AQI\n","\n","def expected_aqi(station):\n","  sis = [0]\n","  for pollutant in pollutant_list:\n","    value = station[pollutant]\n","    try: sis.append(subindex(pollutant,value))\n","    except: pass\n","  return max(sis)\n","\n","def detect_aqi_mismatch(station):\n","  expected = expected_aqi(station)\n","  if pd.isna(expected):\n","    return False\n","\n","  reported = station[\"AQI\"]\n","  if pd.isna(reported):\n","    return False\n","\n","  if abs(reported - expected) > 50:\n","    return True\n","  return False"],"metadata":{"id":"dW5K-C9BRVXc","executionInfo":{"status":"ok","timestamp":1768654291525,"user_tz":-330,"elapsed":14,"user":{"displayName":"Aayush","userId":"13805432364675088607"}}},"execution_count":2,"outputs":[]},{"cell_type":"markdown","source":["Data Summarization"],"metadata":{"id":"33hcM8HniOZi"}},{"cell_type":"code","source":["f = open('/content/drive/MyDrive/Jagriti/station_hour.csv','r')\n","cols = f.readline().strip().split(',')\n","pollutant_list = cols[2:-1]\n","chunk = 200000\n","\n","print(cols)\n","\n","for i in pd.read_csv(f,chunksize=chunk,header=None,names=cols,dtype={'StationId': 'string','AQI_Bucket': 'string'},parse_dates=['Datetime'], na_values=['','-','na','NA','null','NaN']):\n","\n","  #parse the datetime and set up helper column - Season\n","  i['Season'] = i['Datetime'].dt.month.apply(season)\n","  i.sort_values(by=['StationId', 'Datetime'],inplace=True)\n","  current_stations = set(i['StationId'])\n","  station_set.update(current_stations)\n","\n","  #total counts\n","  station_counts = i['StationId'].value_counts()\n","  for station, count in station_counts.items():\n","    station_total_count[station] = station_total_count.get(station, 0) + count\n","\n","  #completeness\n","  for pollutant in pollutant_list:\n","    # Total number of entries\n","    total_counts = i.groupby(['StationId', 'Season'])[pollutant].size()\n","    for (station, season_name), count in total_counts.items():\n","      master[station][pollutant][season_name][\"total\"] += count\n","\n","    # Total non-blank counts (actual) per Station-Pollutant-Season\n","    actual_counts = i.groupby(['StationId', 'Season'])[pollutant].count()\n","    for (station, season_name), count in actual_counts.items():\n","      master[station][pollutant][season_name][\"actual\"] += count\n","\n","    # Validation: negative values\n","    invalid_rows = i[i[pollutant] < 0]\n","    invalid_counts = invalid_rows.groupby(['StationId', 'Season'])[pollutant].size()\n","    for (station, season_name), count in invalid_counts.items():\n","      master[station][pollutant][season_name][\"invalid\"] += count\n","\n","    # Validation: range bounds\n","    for pol, bound in upper_bounds.items():\n","      invalid_mask = i[pol] > bound\n","      invalid_counts = i[invalid_mask].groupby(['StationId','Season']).size()\n","      for (station, season_name), count in invalid_counts.items():\n","        master[station][pol][season_name][\"invalid\"] += count\n","\n","\n","  # Validation : PM2.5 < PM10\n","  invalid_pm_mask = ((i['PM2.5'] > i['PM10']) & (i['PM2.5'] >= 0) & (i['PM10'] >= 0) & i['PM2.5'].notna() & i['PM10'].notna())\n","  invalid_pm_rows = i[invalid_pm_mask]\n","  invalid_pm_counts = invalid_pm_rows.groupby(['StationId', 'Season']).size()\n","  for (station, season_name), count in invalid_pm_counts.items():\n","    master[station]['PM2.5'][season_name][\"invalid\"] += count\n","    master[station]['PM10'][season_name][\"invalid\"] += count\n","\n","  # Validation : NOx > NO+NO2\n","  invalid_no_mask = (i['NOx'].notna() & i['NO'].notna() & i['NO2'].notna() & (i['NOx'] >= 0) & (i['NO'] >= 0) & (i['NO2'] >= 0) & (i['NOx'] > i['NO'] + i['NO2']))\n","  invalid_no_rows = i[invalid_no_mask]\n","  invalid_no_counts = invalid_no_rows.groupby(['StationId', 'Season']).size()\n","  for (station, season_name), count in invalid_no_counts.items():\n","    master[station]['NOx'][season_name][\"invalid\"] += count\n","    master[station]['NO'][season_name][\"invalid\"] += count\n","    master[station]['NO2'][season_name][\"invalid\"] += count\n","\n","  # Validation : AQI\n","  invalid_aqi_mask = i.apply(lambda station: detect_aqi_mismatch(station), axis=1)\n","  invalid_aqi_rows = i[invalid_aqi_mask]\n","  invalid_aqi_counts = invalid_aqi_rows.groupby(['StationId', 'Season']).size()\n","  for (station, season_name), count in invalid_aqi_counts.items():\n","    master[station]['AQI'][season_name][\"invalid\"] += count\n","\n","  # outage counts\n","  pollutant_values = i[pollutant_list].fillna(0)\n","  row_has_any_data = (pollutant_values!=0).any(axis=1)\n","  i[\"is_outage\"] = ~row_has_any_data\n","\n","  outage_counts = i.groupby([\"StationId\",\"Season\"])[\"is_outage\"].sum()\n","\n","  for (station, season_name), count in outage_counts.items():\n","    station_outage_count[station][season_name] += count\n","\n","  #outage blocks\n","\n","  for station in current_stations:\n","    df_station = i[i[\"StationId\"] == station]\n","    arr = df_station[\"is_outage\"].to_numpy()\n","    seasons_arr = df_station[\"Season\"].to_numpy()\n","    current_run = 0\n","\n","    if station in last_status and last_status[station] == True:\n","      current_run = last_run_length[station]\n","      if arr[0] == False:\n","        season_name = last_season[station]\n","        station_outage_blocks[station][season_name].append(current_run)\n","        current_run = 0\n","\n","    for j in range(len(arr)):\n","      if arr[j] == True:\n","        current_run += 1\n","      else:\n","        if current_run>0:\n","          if j!=0:\n","            season_name = seasons_arr[j-1]\n","            station_outage_blocks[station][season_name].append(current_run)\n","            current_run = 0\n","\n","    last_status[station] = arr[-1]\n","    last_run_length[station] = current_run\n","    last_season[station] = season_name\n","f.close()\n","\n","for station in last_status:\n","  if last_status[station] == True and last_run_length[station]  > 0:\n","    season_name = last_season.get(station,'')\n","    station_outage_blocks[station][season_name].append(last_run_length[station])"],"metadata":{"colab":{"base_uri":"https://localhost:8080/","height":216},"id":"O-stE3B0o5wy","executionInfo":{"status":"error","timestamp":1768654292367,"user_tz":-330,"elapsed":831,"user":{"displayName":"Aayush","userId":"13805432364675088607"}},"outputId":"304535c4-a37a-4409-8522-43ef10e71801"},"execution_count":3,"outputs":[{"output_type":"error","ename":"FileNotFoundError","evalue":"[Errno 2] No such file or directory: '/content/drive/MyDrive/Jagriti/station_hour.csv'","traceback":["\u001b[0;31m---------------------------------------------------------------------------\u001b[0m","\u001b[0;31mFileNotFoundError\u001b[0m                         Traceback (most recent call last)","\u001b[0;32m/tmp/ipython-input-3966778109.py\u001b[0m in \u001b[0;36m<cell line: 0>\u001b[0;34m()\u001b[0m\n\u001b[0;32m----> 1\u001b[0;31m \u001b[0mf\u001b[0m \u001b[0;34m=\u001b[0m \u001b[0mopen\u001b[0m\u001b[0;34m(\u001b[0m\u001b[0;34m'/content/drive/MyDrive/Jagriti/station_hour.csv'\u001b[0m\u001b[0;34m,\u001b[0m\u001b[0;34m'r'\u001b[0m\u001b[0;34m)\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n\u001b[0m\u001b[1;32m      2\u001b[0m \u001b[0mcols\u001b[0m \u001b[0;34m=\u001b[0m \u001b[0mf\u001b[0m\u001b[0;34m.\u001b[0m\u001b[0mreadline\u001b[0m\u001b[0;34m(\u001b[0m\u001b[0;34m)\u001b[0m\u001b[0;34m.\u001b[0m\u001b[0mstrip\u001b[0m\u001b[0;34m(\u001b[0m\u001b[0;34m)\u001b[0m\u001b[0;34m.\u001b[0m\u001b[0msplit\u001b[0m\u001b[0;34m(\u001b[0m\u001b[0;34m','\u001b[0m\u001b[0;34m)\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n\u001b[1;32m      3\u001b[0m \u001b[0mpollutant_list\u001b[0m \u001b[0;34m=\u001b[0m \u001b[0mcols\u001b[0m\u001b[0;34m[\u001b[0m\u001b[0;36m2\u001b[0m\u001b[0;34m:\u001b[0m\u001b[0;34m-\u001b[0m\u001b[0;36m1\u001b[0m\u001b[0;34m]\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n\u001b[1;32m      4\u001b[0m \u001b[0mchunk\u001b[0m \u001b[0;34m=\u001b[0m \u001b[0;36m200000\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n\u001b[1;32m      5\u001b[0m \u001b[0;34m\u001b[0m\u001b[0m\n","\u001b[0;31mFileNotFoundError\u001b[0m: [Errno 2] No such file or directory: '/content/drive/MyDrive/Jagriti/station_hour.csv'"]}]},{"cell_type":"markdown","source":["Compilation of results"],"metadata":{"id":"SE4cKvFRP2b4"}},{"cell_type":"code","source":["records_outage = []\n","records_pollutants = []\n","records_summary = []\n","\n","for station in station_set:\n","  seasons = [\"Winter\", \"Summer\", \"Monsoon\", \"Autumn\"]\n","  station_total_hours = station_total_count.get(station, 0)\n","\n","  for season_name in seasons:\n","    outage_hours = station_outage_count[station].get(season_name, 0)\n","    outage_blocks = station_outage_blocks[station].get(season_name, [])\n","\n","    num_outages = len(outage_blocks)\n","    max_outage = max(outage_blocks) if outage_blocks else 0\n","    avg_outage = sum(outage_blocks)/num_outages if outage_blocks else 0\n","    day_outages = sum(1 for b in outage_blocks if b >= 24)\n","\n","    actual_hours = sum(master[station][p][season_name]['actual'] for p in pollutant_list)\n","    invalid_hours = sum(master[station][p][season_name]['invalid'] for p in pollutant_list)\n","    total_hours = sum(master[station][p][season_name]['total'] for p in pollutant_list)\n","    season_total_hours = master[station]['AQI'][season_name]['total']\n","    completeness = actual_hours/total_hours if total_hours > 0 else 0\n","    validness = 1-(invalid_hours/actual_hours) if actual_hours > 0 else 0\n","    uptime = (season_total_hours-outage_hours)/season_total_hours if season_total_hours > 0 else 0\n","\n","    if season_total_hours==0:\n","      pass\n","    else:\n","      records_summary.append({\n","        'StationId': station,\n","        'Season': season_name,\n","        'TotalHours': season_total_hours,\n","        'Completeness': completeness,\n","        'Validness': validness,\n","        'Uptime': uptime,\n","        'Score': 0.5*completeness + 0.2*uptime + 0.3*validness})\n","      records_outage.append({\n","        'StationId': station,\n","        'Season': season_name,\n","        'TotalHours': station_total_hours,\n","        'OutageHours': outage_hours,\n","        'NumOutages': num_outages,\n","        'MaxOutage': max_outage,\n","        'AvgOutage': avg_outage,\n","        'Outages>24hr': day_outages,})\n","\n","    for pollutant in pollutant_list:\n","      data = master[station][pollutant].get(season_name, {\"actual\":0,\"total\":0,\"invalid\":0})\n","      records_pollutants.append({\n","        'StationId': station,\n","        'Season': season_name,\n","        'Pollutant': pollutant,\n","        'Actual': data['actual'],\n","        'Total': data['total'],\n","        'Invalid': data['invalid']})\n","\n","final_df_outage = pd.DataFrame(records_outage)\n","final_df_pollutant = pd.DataFrame(records_pollutants)\n","final_df_summary = pd.DataFrame(records_summary)\n"],"metadata":{"id":"LDcycDzniMGK"},"execution_count":null,"outputs":[]},{"cell_type":"code","source":["with open('/content/drive/MyDrive/Jagriti/station_performance_outage.csv',\"w\") as f:\n","  f.write(final_df_outage.to_csv())\n","with open('/content/drive/MyDrive/Jagriti/station_performance_pollutant.csv',\"w\") as f:\n","  f.write(final_df_pollutant.to_csv())\n","with open('/content/drive/MyDrive/Jagriti/station_performance_summary.csv',\"w\") as f:\n","  f.write(final_df_summary.to_csv())"],"metadata":{"id":"yAUOSltzRL8R"},"execution_count":null,"outputs":[]}]}